        new Recipe { Id = 6, Title = "Sushi Rolls", Category = "Japanese", Ingredients = "Sushi rice\nRice vinegar\nNori sheets\nFresh salmon or tuna\nCucumber\nAvocado\nSoy sauce\nWasabi\nPickled ginger", Steps = "1. Cook sushi rice and season with rice vinegar.\n2. Place nori on bamboo mat, spread rice evenly.\n3. Lay fish and vegetables in a line.\n4. Roll tightly using the mat.\n5. Slice with a wet knife.\n6. Serve with soy sauce, wasabi, and ginger.", AverageRating = 4.7, RatingCount = 18 },
    };

    private static readonly List<RecipeCategory> _categories = new()
    {
        new RecipeCategory { Name = "Italian", Description = "Classic pasta, pizza, and Mediterranean flavors", Icon = "🍝" },
        new RecipeCategory { Name = "Indian", Description = "Rich curries, spices, and aromatic dishes", Icon = "🍛" },
        new RecipeCategory { Name = "Mexican", Description = "Bold flavors with tacos, salsas, and more", Icon = "🌮" },
        new RecipeCategory { Name = "Thai", Description = "Sweet, sour, salty, and spicy balance", Icon = "🍜" },
        new RecipeCategory { Name = "French", Description = "Elegant techniques and rich sauces", Icon = "🥐" },
        new RecipeCategory { Name = "Japanese", Description = "Fresh ingredients and precise preparation", Icon = "🍣" },
    };

