@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category yet.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="text-muted">
                            ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<RecipeCommunity.Models.Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Components.Shared
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <div class="row">
        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <div class="card-body">
                    <ul class="list-unstyled mb-0">
                        @foreach (var ingredient in recipe.Ingredients.Split('\n'))
                        {
                            <li>• @ingredient</li>
                        }
                    </ul>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Steps</h5></div>
                <div class="card-body">
                    @foreach (var step in recipe.Steps.Split('\n'))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">Rate This Recipe</h5></div>
                <div class="card-body">
                    <p class="text-muted mb-2">
                        Average: ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                    </p>
                    <StarRating RecipeId="recipe.Id" />
                </div>
