toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success">@successMessage</div>
}

<EditForm Model="newRecipe" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label class="form-label">Title</label>
        <InputText @bind-Value="newRecipe.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
    </div>

    <div class="mb-3">
        <label class="form-label">Category</label>
        <InputSelect @bind-Value="newRecipe.Category" class="form-select">
            <option value="">-- Select a category --</option>
            @foreach (var cat in RecipeService.GetCategories())
            {
                <option value="@cat.Name">@cat.Name</option>
            }
        </InputSelect>
    </div>

    <div class="mb-3">
        <label class="form-label">Ingredients (one per line)</label>
        <InputTextArea @bind-Value="newRecipe.Ingredients" class="form-control" rows="5"
                       placeholder="Flour&#10;Sugar&#10;Butter&#10;Apples" />
    </div>

    <div class="mb-3">
        <label class="form-label">Steps (one per line)</label>
        <InputTextArea @bind-Value="newRecipe.Steps" class="form-control" rows="6"
                       placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients..." />
    </div>

    <button type="submit" class="btn btn-success">Submit Recipe</button>
</EditForm>

@code {
    private Recipe newRecipe = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(newRecipe.Title) ||
            string.IsNullOrWhiteSpace(newRecipe.Category) ||
            string.IsNullOrWhiteSpace(newRecipe.Ingredients) ||
            string.IsNullOrWhiteSpace(newRecipe.Steps))
        {
            return;
        }

        RecipeService.SubmitRecipe(newRecipe);
        successMessage = $"'{newRecipe.Title}' submitted successfully!";
        newRecipe = new();
    }
}

